{"content":"package ru.samtakoy.stocks.core.network.di

import io.ktor.client.HttpClient
import io.ktor.client.plugins.contentnegotiation.ContentNegotiation
import io.ktor.serialization.kotlinx.json.json
import org.koin.dsl.module

val networkModule = module {
    single {
        HttpClient {
            install(ContentNegotiation) { json() }
        }
    }
}
"}

{"content":"package ru.samtakoy.stocks.core.db.di

import org.koin.dsl.module
import ru.samtakoy.stocks.core.db.StocksDatabase

val dbModule = module {
    single { StocksDatabase(driver = get()) }
}
"}

{"content":"package ru.samtakoy.stocks.features.auth.di

import org.koin.dsl.module
import ru.samtakoy.stocks.features.auth.AuthRepository
import ru.samtakoy.stocks.features.auth.AuthRepositoryImpl

val authModule = module {
    single<AuthRepository> { AuthRepositoryImpl(httpClient = get()) }
}
"}
